// --- SETTINGS ---
const MAX_REVIEWS = 50000;
// ------------------

const newItems = [];
const cleanPhone = (p) => p ? p.replace(/[^0-9]/g, '') : '';

const processEntry = (entry) => {
  if (!entry || typeof entry !== 'object') return;

  // Normalize fields
  entry.website = (entry.site || entry.website || '').trim();
  if (entry.website === '') entry.website = null;

  entry.email = (entry.email || '').trim();
  if (entry.email === '') entry.email = null;

  entry.name = (entry.name || 'Unnamed Lead').trim();
  entry.reviews = entry.reviews || 0;
  entry.clean_phone = cleanPhone(entry.phone);

  // EXTRACT RELEVANT REVIEWS
  let reviewsList = [];
  if (Array.isArray(entry.reviews_data)) {
    reviewsList = entry.reviews_data
        .filter(r => r.review_text && r.review_text.length > 5)
        .map(r => `(${r.review_rating}★) "${r.review_text}"`)
        .slice(0, 10);
  }

  entry.reviews_context = reviewsList.length > 0 
    ? reviewsList.join('\n') 
    : 'No text reviews.';

  const isNew = entry.reviews < MAX_REVIEWS;
  if (isNew) {
    newItems.push({ json: entry });
  }
};

for (const item of items) {
  let data = item.json.data || item.json;
  if (Array.isArray(data)) {
    if (Array.isArray(data[0])) data = data.flat();
    data.forEach(processEntry);
  } else if (typeof data === 'object') {
    Object.keys(data).forEach(key => {
      const val = data[key];
      if (val && typeof val === 'object' && (val.name || val.place_id)) {
        processEntry(val);
      }
    });
  }
}

return newItems;

