// 1. RANDOMIZER
const intros = [
  "🔥 <b>New Lead!</b>",
  "🚀 <b>Who wants this one?</b>",
  "👀 <b>Interesting case.</b>",
  "⚡️ <b>Potential partner.</b>"
];
const randomIntro = intros[Math.floor(Math.random() * intros.length)];

// 2. DATA
const sourceData = $('🔗 Merge Final').item.json;
const notionId = $('💾 Create New Lead').item.json.id;
const notionUrl = $('💾 Create New Lead').item.json.url;

// ESCAPE
const escape = (str) => str ? str.toString().replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;') : '';

// 3. MESSAGE BUILD
const message = `
${randomIntro}

📍 ${sourceData.city} | 🏢 <b>${escape(sourceData.name)}</b>
⭐️ <b>${sourceData.rating}</b> (${sourceData.reviews} reviews)

🎯 <b>Strategy:</b>
<i>${escape(sourceData.message.content)}</i>

📞 <code>${sourceData.clean_phone}</code>
🌐 <a href="${sourceData.website}">Site</a> | 🗺 <a href="${sourceData.link || sourceData.location_link}">Maps</a>

👇 <b>Action:</b>
<a href="${notionUrl}">📂 Open in CRM</a>
`;

return {
  json: {
    telegram_message: message,
    lead_id: notionId
  }
};
